import { Component, computed, input } from '@angular/core';

interface HitoConfigView {
  hitoConfigId: number;
  hitoId: number;
  nombre: string;
  carril: string;
  grupoParalelo: { id: number; nombre: string } | null;
  orden: number;
  activo: boolean;
  subetapas: SubetapaConfigView[];
}

interface SubetapaConfigView {
  subetapaConfigId: number | null;
  subetapaId: number;
  nombre: string;
  categoria: string;
  campoStagingVin: string | null;
  orden: number;
  activo: boolean;
}

interface Bloque {
  grupoId: number;
  label: string;
  hitos: { nombre: string; carril: string; subetapas: string[] }[];
}

@Component({
  selector: 'kf-process-preview',
  standalone: true,
  imports: [],
  template: `
  <div class="bg-white rounded-lg border border-slate-200 p-6 overflow-x-auto">
    <h3 class="text-sm font-semibold text-slate-700 mb-5">Vista previa del proceso</h3>

    <!-- Pipeline flow -->
    <div class="flex items-start gap-0 flex-nowrap min-w-max">
      @for (bloque of bloques(); track bloque.grupoId; let last = $last) {

        <!-- Grupo block -->
        <div class="flex flex-col items-center">
          <!-- Grupo label -->
          <span class="text-xs font-semibold text-slate-400 mb-2">{{ bloque.label }}</span>

          <!-- Hitos within the grupo (side by side if multiple) -->
          <div class="flex items-start gap-3">
            @for (hito of bloque.hitos; track hito.nombre) {
              <div class="flex flex-col items-center min-w-32 max-w-44">
                <!-- Node circle -->
                <div class="w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all"
                  [class]="hito.carril === 'financiero'
                    ? 'border-blue-400 bg-blue-50 text-blue-600'
                    : 'border-amber-400 bg-amber-50 text-amber-600'">
                  <svg class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
                    <circle cx="12" cy="12" r="5" />
                  </svg>
                </div>

                <!-- Hito name -->
                <span class="mt-1.5 text-xs font-semibold text-slate-700 text-center leading-tight">
                  {{ hito.nombre }}
                </span>

                <!-- Subetapas list -->
                @if (hito.subetapas.length > 0) {
                  <div class="mt-2 w-full bg-slate-50 rounded-md border border-slate-100 px-2 py-1.5">
                    @for (sub of hito.subetapas; track sub; let si = $index) {
                      <div class="flex items-center gap-1.5 py-0.5">
                        <span class="w-1 h-1 rounded-full bg-slate-300 shrink-0"></span>
                        <span class="text-xs text-slate-500 leading-tight truncate" [title]="sub">{{ sub }}</span>
                      </div>
                    }
                  </div>
                }
              </div>
            }
          </div>
        </div>

        <!-- Arrow connector -->
        @if (!last) {
          <div class="flex items-center self-center mt-7 mx-1 shrink-0">
            <div class="w-6 h-0.5 bg-slate-300"></div>
            <div class="w-0 h-0 border-t-4 border-b-4 border-l-4 border-transparent border-l-slate-300"></div>
          </div>
        }
      }
    </div>

    <!-- Legend -->
    <div class="mt-6 pt-4 border-t border-slate-100 flex flex-wrap gap-4 text-xs text-slate-500">
      <span class="flex items-center gap-1.5">
        <span class="w-3 h-3 rounded-full border-2 border-blue-400 bg-blue-50"></span> Financiero
      </span>
      <span class="flex items-center gap-1.5">
        <span class="w-3 h-3 rounded-full border-2 border-amber-400 bg-amber-50"></span> Operativo
      </span>
      <span class="flex items-center gap-1.5">
        <svg class="w-3.5 h-3.5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
          <path stroke-linecap="round" stroke-linejoin="round" d="M13 7l5 5-5 5M6 12h12"/>
        </svg>
        Secuencia entre grupos
      </span>
    </div>
  </div>
  `,
})
export class ProcessPreviewComponent {
  hitos = input.required<HitoConfigView[]>();

  bloques = computed(() => {
    const active = this.hitos().filter(h => h.activo).sort((a, b) => a.orden - b.orden);

    const grupoMap = new Map<number, HitoConfigView[]>();
    for (const h of active) {
      const gid = h.grupoParalelo?.id ?? 0;
      if (!grupoMap.has(gid)) grupoMap.set(gid, []);
      grupoMap.get(gid)!.push(h);
    }

    const result: Bloque[] = [...grupoMap.entries()]
      .map(([gid, hitos]) => ({
        grupoId: gid,
        label: '',
        minOrden: Math.min(...hitos.map(h => h.orden)),
        hitos: hitos.map(h => ({
          nombre: h.nombre,
          carril: h.carril,
          subetapas: h.subetapas.filter(s => s.activo).sort((a, b) => a.orden - b.orden).map(s => s.nombre),
        })),
      }))
      .sort((a, b) => a.minOrden - b.minOrden);

    result.forEach((b, i) => b.label = `Grupo ${i + 1}`);

    return result;
  });
}
